        // �������
        function adjustImage(param, value) {
            var dev = connectedDevice.ip;
            if (!dev) return;
            // ���ڻ������UI������ʵ�ʿ�����ISAPI���� (������)
            var labels = {brightness:'����',contrast:'�Աȶ�',saturation:'���Ͷ�'};
            var label = labels[param] || param;
            // ռλ����ʾ��ǰֵ
            console.log('[�������] ' + label + ': ' + value);
        }
        // OSD ������ʾ����
        function toggleOsd(enabled) {
            var dev = connectedDevice.ip;
            if (!dev) { showToast('warning', '����ѡ���豸'); return; }
            apiPost('/api/v1/ptz/' + dev + '/osd/toggle?enabled=' + enabled, null).then(function(result) {
                if (result && result.success) {
                    showToast('success', result.message);
                    document.getElementById('btnOsdOn').className = enabled ? 'btn btn-sm btn-primary' : 'btn btn-sm btn-secondary';
                    document.getElementById('btnOsdOff').className = enabled ? 'btn btn-sm btn-secondary' : 'btn btn-sm btn-primary';
                } else {
                    showToast('error', result ? result.message : 'OSD �л�ʧ��');
                }
            }).catch(function(e) { showToast('error', 'OSD �л��쳣: ' + e.message); });
        }
        // �佹����
        function ptzZoom(direction) {
            var dev = connectedDevice.ip;
            if (!dev) { showToast('warning', '����ѡ���豸'); return; }
            var speed = parseInt(document.getElementById('ptzSpeed').value);
            apiPost('/api/v1/ptz/' + dev + '/move', {
                direction: direction === 'in' ? 'zoom-in' : 'zoom-out',
                speed: speed
            }).catch(function(e) { addLog('info', 'PTZ �佹: ' + direction); });
        }
        // �Խ�����
        function ptzFocus(mode) {
            var dev = connectedDevice.ip;
            if (!dev) { showToast('warning', '����ѡ���豸'); return; }
            var dir = mode === 'auto' ? 'focus-auto' : mode === 'near' ? 'focus-near' : 'focus-far';
            apiPost('/api/v1/ptz/' + dev + '/move', {
                direction: dir,
                speed: parseInt(document.getElementById('ptzSpeed').value)
            }).catch(function(e) { addLog('info', 'PTZ �Խ�: ' + mode); });
        }
        // ================================================================
        //  BUG-017 �޸�: ��¶������ȫ�� window��ʹ HTML onclick �ɵ���
        //  �豸����ҳ�水ť������/����/ˢ�£��Լ�����ҳ�潻����
        //  onclick ������������ IIFE �ڲ���������ʽ��¶��ȫ�֡�
        // ================================================================
        var _expose = [
            discoverDevices, refreshDevices,
            connectDevice, disconnectDevice, deleteDevice,
            ptzMove, ptzHome, ptzStop, getPtzPosition, onPtzDeviceChange,
            calibrate, saveSettings,
            funcDetectRun, funcDetectRestore,
            limitTestRun, speedTestRun,
            streamStart, streamStop, recordStart, recordStop, snapshotCapture,
            onStreamDeviceChange, resetStreamButtons,
            presetGoto, presetSet, startDetection,
            connectFuncDetectRun, connectLimitTestRun, connectSpeedTestRun,
            // ����̨���� (�޸�6)
            setTracking, consoleSnapshot, consoleRecordStart, consoleRecordStop,
             adjustImage, toggleOsd,
            ptzZoom, ptzFocus,
            // Ԥ�õ��б�����
            loadPresetList, ptzGotoSelectedPreset, ptzSetSelectedPreset,
            addDeviceInline, modifyIpPrompt, showDeviceInfoInline,
        ];
        _expose.forEach(function(fn) { window[fn.name] = fn; });
        // Go! - init() executes immediately for instant page interaction
        init();
        function loadWasmDevices() {
            var sel = document.getElementById('device-select');
            if (!sel) return;
            var currentVal = sel.value;
            apiGet('/api/v1/devices').then(function(resp) {
                var devices = resp && resp.success ? (resp.data || resp.devices || []) : [];
                allDevices = devices;
                var ptzDevices = devices.filter(function(d) { return d.online && (d.type === 'ptz' || d.ptz === true); });
                sel.innerHTML = '<option value="">-- ѡ�� PTZ �豸 --</option>';
                ptzDevices.forEach(function(d) {
                    var opt = document.createElement('option');
                    opt.value = d.ip;
                    opt.textContent = ((d.model ? d.model + ' ' : '') + (d.name || d.device_name || d.ip)).trim() + ' (' + d.ip + ')';
                    sel.appendChild(opt);
                });
                if (currentVal && sel.querySelector('option[value="' + currentVal + '"]')) {
                    sel.value = currentVal;
                }
            }).catch(function(e) {
                console.warn('[WASM] Failed to load devices:', e);
                sel.innerHTML = '<option value="">-- ����ʧ�� --</option>';
            });
        }
        function wasmLogout() {
            if (!g_bLoggedIn) return;
            try {
                stopConsoleStream();
                WebVideoCtrl.I_Logout(g_szDeviceIdentify);
            } catch(e) {}
            g_bLoggedIn = false;
            g_szDeviceIdentify = '';
            g_bPlaying = false;
            setLoginStatus('�ѵǳ�', '#8b949e');
            document.getElementById('login-btn').textContent = '��¼';
        }
        // Inline helpers (no modal)
        function addDeviceInline() {
            var ip = prompt("\u8bbe\u5907 IP:");
            if (!ip) return;
            apiPost("/api/v1/devices", { ip: ip }).then(function(r) {
                if (r && r.success) { showToast("success", "\u5df2\u6dfb\u52a0"); refreshDevices(); }
                else showToast("error", r ? r.message : "\u5931\u8d25");
            }).catch(function(e) { showToast("error", e.message); });
        }
        function modifyIpPrompt(mac, oldIp) {
            var newIp = prompt("IP (MAC: " + mac + ")", oldIp);
            if (!newIp || newIp === oldIp) return;
            apiPost("/api/v1/devices/" + oldIp, { ip: newIp, mac: mac }).then(function(r) {
                if (r && r.success) { showToast("success", "IP \u5df2\u4fee\u6539"); refreshDevices(); }
                else showToast("error", r ? r.message : "\u5931\u8d25");
            }).catch(function(e) { showToast("error", e.message); });
        }
        function showDeviceInfoInline(ip) {
            var el = document.getElementById("deviceInfoPanel");
            if (!el) return;
            el.style.display = "block";
            el.innerHTML = "\u83b7\u53d6\u4e2d...";
            apiGet("/api/v1/devices/" + ip + "/info").then(function(info) {
                if (info && info.success) {
                    var d = info.data || {};
                    el.innerHTML = Object.keys(d).map(function(k) { return "<div><b>" + k + ":</b> " + d[k] + "</div>"; }).join("");
                } else el.innerHTML = "\u65e0\u6cd5\u83b7\u53d6";
            }).catch(function() { el.innerHTML = "\u5931\u8d25"; });
        }
    })();
</script>
