    <script src="static/websdk/wasm/jsPlugin-3.0.0.min.js"></script>
    <script>
    // WASM SDK Initialization (GLOBAL scope)
    (function() {
        function initWasm() {
            var iRet = window.WebVideoCtrl.I_SupportNoPlugin();
            console.log('[WASM] I_SupportNoPlugin:', iRet);
            if (!iRet) {
                console.error('[WASM] Browser does not support noPlugin mode');
                return;
            }
            WebVideoCtrl.I_InitPlugin("100%", "100%", {
                bWndFull: true,
                iPackageType: 2,
                iWndowType: 1,
                bNoPlugin: true,
                cbEvent: function(iEventType, iParam1, iParam2) {
                    console.log("[WASM] Event:", iEventType, iParam1, iParam2);
                },
                cbDoubleClickWnd: function(iWndIndex, bFullScreen) {
                    WebVideoCtrl.I_Stop();
                },
                cbSelWnd: function(xmlDoc) {
                    g_iWndIndex = parseInt($(xmlDoc).find("SelectWnd").eq(0).text(), 10);
                },
                cbInitPluginComplete: function() {
                    console.log('[WASM] cbInitPluginComplete - inserting plugin');
                    WebVideoCtrl.I_InsertOBJECTPlugin("divPlugin");
                    // WASM SDK ready - login/play happens when user clicks connect
                },
                cbPluginErrorHandler: function(iWndIndex, iErrorCode, oError) {
                    console.error('[WASM] Plugin error:', iWndIndex, iErrorCode);
                },
                cbPerformanceLack: function() {
                    console.error('[WASM] Performance issue');
                }
            });
            console.log('[WASM] I_InitPlugin called');
        }
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', initWasm);
        } else {
            initWasm();
        }
    })();
</script>
